<?php

/**
 * Isolated regression test for the generated OpenAPI specification.
 *
 * swagger/openemr-api.yaml is generated by CreateAPIDocumentationCommand. A Security Requirement
 * Object's value is a list of scope names, so an empty requirement must serialize as an array
 * ([]) and never as an object ({}). This test fails if the spec is regenerated without the
 * DUMP_EMPTY_ARRAY_AS_SEQUENCE dump flag.
 *
 * @package   OpenEMR
 * @link      https://www.open-emr.org
 * @author    Aaron Paterson <apaterson@pm.me>
 * @copyright Copyright (c) 2026 Aaron Paterson <apaterson@pm.me>
 * @license   https://github.com/openemr/openemr/blob/master/LICENSE GNU General Public License 3
 */

declare(strict_types=1);

namespace OpenEMR\Tests\Isolated;

use PHPUnit\Framework\TestCase;
use Symfony\Component\Yaml\Yaml;

class SwaggerSpecConformanceTest extends TestCase
{
    private const HTTP_METHODS = ['get', 'put', 'post', 'delete', 'patch', 'options', 'head', 'trace'];

    private string $specFile;

    protected function setUp(): void
    {
        $this->specFile = dirname(__DIR__, 3) . '/swagger/openemr-api.yaml';
    }

    public function testSpecificationParsesAndDefinesPaths(): void
    {
        $this->assertFileExists($this->specFile);
        $spec = Yaml::parseFile($this->specFile);
        $this->assertIsArray($spec);
        $this->assertNotEmpty($spec['paths'] ?? [], 'the generated spec must define paths');
    }

    public function testEmptySecurityRequirementsAreArraysNotObjects(): void
    {
        // PARSE_OBJECT_FOR_MAP maps a YAML mapping ({}) to a stdClass and leaves a sequence ([]) as
        // a PHP array, so an empty security requirement mis-serialized as {} is distinguishable
        // from the correct [].
        $spec = Yaml::parseFile($this->specFile, Yaml::PARSE_OBJECT_FOR_MAP);

        foreach ($spec->paths as $path => $pathItem) {
            foreach (self::HTTP_METHODS as $method) {
                if (!isset($pathItem->$method->security)) {
                    continue;
                }
                foreach ($pathItem->$method->security as $requirement) {
                    foreach (get_object_vars($requirement) as $scheme => $scopes) {
                        $this->assertIsArray(
                            $scopes,
                            sprintf(
                                'security scheme "%s" on %s %s must serialize as an array of scopes, not an object',
                                $scheme,
                                strtoupper($method),
                                $path
                            )
                        );
                    }
                }
            }
        }
    }
}
